        cnt = [0] * 10
        for d in digits:
            cnt[d] += 1

        ans = []
        for x in range(100, 1000, 2):
            a = x // 100
            b = (x // 10) % 10
            c = x % 10

            cnt[a] -= 1
            if cnt[a] >= 0:
                cnt[b] -= 1
                if cnt[b] >= 0:
                    cnt[c] -= 1
                    if cnt[c] >= 0:
                        ans.append(x)
                    cnt[c] += 1
                cnt[b] += 1
            cnt[a] += 1

        return ans
