class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        freq = [0] * 10
        for d in digits:
            freq[d] += 1

        ans = []
        for i in range(100, 1000, 2):
            a = i // 100
            b = (i // 10) % 10
            c = i % 10

            if a == b == c:
                if freq[a] >= 3:
                    ans.append(i)
            elif a == b:
                if freq[a] >= 2 and freq[c] >= 1:
                    ans.append(i)
            elif a == c:
                if freq[a] >= 2 and freq[b] >= 1:
                    ans.append(i)
            elif b == c:
                if freq[b] >= 2 and freq[a] >= 1:
                    ans.append(i)
            else:
                if freq[a] and freq[b] and freq[c]:
                    ans.append(i)
        return ans
