        ans = cnt = 0
        while n:
            if n & 1:
                cnt += 1
            elif cnt:
                ans += 1 if cnt == 1 else 2
                cnt = 0
            n >>= 1
        return ans + (1 if cnt == 1 else 2 if cnt > 1 else 0)
